import React, { useState } from "react";

const Dropdown = ({ key_name, items, selectedValue, setSelectedValue }) => {
    // selected value setting
    const handleChange = (e) => {
        setSelectedValue(e.target.value)
    };

    // return
    return (
        <div>
            <label className="text-sm text-black " htmlFor="dropdown">Select {key_name}: </label>
            <select className="text-xs text-black font-bold bg-gray-200 capitalize py-1 px-2 rounded-md border border-gray-800" name={key_name} id={key_name} value={selectedValue} onChange={handleChange}>
                <option className="font-bold" value="">all</option>
                {items.map((item) => (
                    <option className="font-bold" key={item} value={item}>{item}</option>
                ))}
            </select>
        </div>
    );
};

export default Dropdown;
